from typing import Union


class ASTNode:
    def __init__(self, node_type: str, **kwargs):
        self.type = node_type
        if node_type == 'number':
            self.value = kwargs.get('value')
        elif node_type == 'binop':
            self.op = kwargs.get('op')
            self.left = kwargs.get('left')
            self.right = kwargs.get('right')
        elif node_type == 'unary':
            self.op = kwargs.get('op')
            self.operand = kwargs.get('operand')
        else:
            raise ValueError(f"Unknown node type: {node_type}")

    def __repr__(self):
        if self.type == 'number':
            return f"Number({self.value})"
        elif self.type == 'binop':
            return f"BinOp({self.op}, {self.left}, {self.right})"
        elif self.type == 'unary':
            return f"UnaryOp({self.op}, {self.operand})"
        else:
            return f"ASTNode({self.type})"


class ExpressionParser:
    def __init__(self, expression: str):
        self.expression = expression.replace(' ', '')
        self.pos = 0
        self.current_char = self.expression[self.pos] if self.expression else None

    def advance(self):
        self.pos += 1
        if self.pos >= len(self.expression):
            self.current_char = None
        else:
            self.current_char = self.expression[self.pos]

    def skip_whitespace(self):
        while self.current_char is not None and self.current_char.isspace():
            self.advance()

    def number(self) -> float:
        result = ''
        while (self.current_char is not None and
               (self.current_char.isdigit() or self.current_char == '.')):
            result += self.current_char
            self.advance()

        try:
            return float(result)
        except ValueError:
            raise ValueError(f"Invalid number format: {result}")

    def factor(self) -> ASTNode:
        if self.current_char == '(':
            self.advance()
            node = self.expression_()
            if self.current_char != ')':
                raise ValueError("Unmatched parentheses")
            self.advance()
            return node

        if self.current_char == '-':
            self.advance()
            return ASTNode('unary', op='-', operand=self.factor())

        if self.current_char == '+':
            self.advance()
            return self.factor()

        if self.current_char is None:
            raise ValueError("Empty expression")

        if not self.current_char.isdigit() and self.current_char != '.':
            raise ValueError(f"Invalid token: {self.current_char}")

        value = self.number()
        return ASTNode('number', value=value)

    def term(self) -> ASTNode:
        node = self.factor()

        while self.current_char in ('*', '/'):
            op = self.current_char
            self.advance()
            right = self.factor()
            node = ASTNode('binop', op=op, left=node, right=right)

        return node

    def expression_(self) -> ASTNode:
        node = self.term()

        while self.current_char in ('+', '-'):
            op = self.current_char
            self.advance()
            right = self.term()
            node = ASTNode('binop', op=op, left=node, right=right)

        return node

    def parse(self) -> ASTNode:
        if not self.expression:
            raise ValueError("Empty expression")

        node = self.expression_()

        if self.current_char is not None:
            raise ValueError(f"Unexpected token: {self.current_char}")

        return node


def parse(expression: str) -> ASTNode:
    parser = ExpressionParser(expression)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value

    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")

    elif node.type == 'unary':
        operand_val = evaluate(node.operand)

        if node.op == '-':
            return -operand_val
        elif node.op == '+':
            return operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")

    else:
        raise ValueError(f"Unknown node type: {node.type}")
